text:
@use '../core/style/vendor-prefixes';

// Ensures that the internal chip container spans the entire outer container width, if the
// outer container width is customized. This is used by some wrapper components in g3.
.mat-mdc-chip-set {
  display: flex;

  &:focus {
    outline: none;
  }

  .mdc-evolution-chip-set__chips {
    min-width: 100%;
    margin-left: -8px;
    margin-right: 0;
  }

  .mdc-evolution-chip {
    margin: 4px 0 4px 8px;
  }

  [dir='rtl'] & {
    .mdc-evolution-chip-set__chips {
      margin-left: 0;
      margin-right: -8px;
    }

    .mdc-evolution-chip {
      margin-left: 0;
      margin-right: 8px;
    }
  }
}

.mdc-evolution-chip-set__chips {
  display: flex;
  flex-flow: wrap;
  min-width: 0;
}

// Angular Material supports vertically-stacked chips, which MDC does not.
.mat-mdc-chip-set-stacked {
  flex-direction: column;
  align-items: flex-start;

  .mat-mdc-chip {
    width: 100%;
  }

  .mdc-evolution-chip__graphic {
    flex-grow: 0;
  }

  .mdc-evolution-chip__action--primary {
    flex-basis: 100%;
    justify-content: start;
  }
}

input.mat-mdc-chip-input {
  flex: 1 0 150px;
  margin-left: 8px;

  [dir='rtl'] & {
    margin-left: 0;
    margin-right: 8px;
  }

  // The form field hides the placeholder by default,
  // but we actually want to show it if there are chips.
  .mat-mdc-form-field:not(.mat-form-field-hide-placeholder) & {
    @include vendor-prefixes.input-placeholder {
      opacity: 1;
    }
  }

  // The margin isn't necessary if the input is placed next to the chip set,
  // because it'll be on the next line.
  .mat-mdc-chip-set + & {
    margin-left: 0;
    margin-right: 0;
  }
}

// This mixin will ensure that lines that overflow the container will hide the overflow and
// truncate neatly with an ellipsis.
@mixin truncate-line() {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

// Mixin to provide all mat-line styles, changing secondary font size based on whether the list
// is in dense mode.
@mixin base($secondary-font-size) {
  .mat-line {
    @include truncate-line();
    display: block;
    box-sizing: border-box;

    // all lines but the top line should have smaller text
    &:nth-child(n+2) {
      font-size: $secondary-font-size;
    }
  }
}

// This mixin normalizes default element styles, e.g. font weight for heading text.
@mixin normalize-text() {
  & > * {
    margin: 0;
    padding: 0;
    font-weight: normal;
    font-size: inherit;
  }
}

// This mixin provides base styles for the wrapper around mat-line elements in a list.
@mixin wrapper-base() {
  display: flex;
  flex-direction: column;
  flex: auto;
  box-sizing: border-box;
  overflow: hidden;

  @include normalize-text();

  // Must remove wrapper when lines are empty or it takes up horizontal
  // space and pushes other elements to the right.
  &:empty {
    display: none;
  }
}

&[type='checkbox'] {
  border-radius: $form-check-input-checkbox-border-radius;
  margin-top: 0.19em;
  margin-right: 6px;

  &:focus {
    &:after {
      content: '';
      position: absolute;
      width: $form-check-input-checkbox-focus-after-width;
      height: $form-check-input-checkbox-focus-after-height;
      z-index: 1;
      display: block;
      border-radius: 0;
      background-color: $form-check-input-checkbox-focus-after-background-color;
    }
  }

  &:checked {
    background-image: none;
    background-color: $form-check-input-checkbox-checked-background-color;

    &:after {
      display: block;
      transform: $form-check-input-checkbox-checked-after-transform #{'/*!rtl:ignore*/'};
      border-width: $form-check-input-checkbox-checked-after-border-width;
      border-color: $form-check-input-checkbox-checked-after-border-color;
      width: $form-check-input-checkbox-checked-after-width;
      height: $form-check-input-checkbox-checked-after-height;
      border-style: solid;
      border-top: 0;
      border-left: 0 #{'/*!rtl:ignore*/'};
      margin-left: $form-check-input-checkbox-checked-after-margin-left;
      margin-top: $form-check-input-checkbox-checked-after-margin-top;
      background-color: transparent;
    }

    &:focus {
      background-color: $form-check-input-checkbox-checked-focus-background-color;
    }
  }

  &:indeterminate {
    border-color: $form-check-input-indeterminate-focus-border-color;
  }
}

&[type='radio'] {
  border-radius: $form-check-input-radio-border-radius;
  width: $form-check-input-radio-width;
  height: $form-check-input-radio-height;
  margin-top: 0.125em;
  margin-right: 4px;

  &:before {
    width: $form-check-input-radio-before-width;
    height: $form-check-input-radio-before-height;
  }

  &:after {
    content: '';
    position: absolute;
    width: $form-check-input-radio-after-width;
    height: $form-check-input-radio-after-height;
    z-index: 1;
    display: block;
    border-radius: $form-check-input-radio-after-border-radius;
    background-color: $form-check-input-radio-after-background-color;
  }

  &:checked {
    background-image: none;
    background-color: $form-check-input-radio-checked-background-color;

    &:after {
      border-radius: $form-check-input-radio-checked-after-border-radius;
      width: $form-check-input-radio-checked-after-width;
      height: $form-check-input-radio-checked-after-height;
      border-color: $form-check-input-radio-checked-after-border-color;
      background-color: $form-check-input-radio-checked-after-background-color;
      transition: $form-check-input-radio-checked-after-transition;
      transform: translate(-50%, -50%);
      position: absolute;
      left: 50%;
      top: 50%;
    }

    &:focus {
      background-color: $form-check-input-radio-checked-focus-background-color;
    }
  }
}
